update student
name = #{name}, no = #{no}, phone = #{phone}, gender = #{gender}, id_card = #{idCard}, is_college = #{isCollege}, degree = #{degree}, clazz_id = #{clazzId}, address = #{address}, graduation_date = #{graduationDate}, update_time = #{updateTime}, violation_count = #{violationCount}, violation_score = #{violationScore},
where id = #{id}

mapper.select:
SELECT s.*, c.name AS clazzName FROM student s LEFT JOIN clazz c ON s.clazz_id = c.id
AND s.name LIKE CONCAT('%', #{name}, '%')
AND s.degree = #{degree}
AND s.clazz_id = #{clazzId}
